generated_oml:
// C3: Physical sensing components
instance MotorMountedEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted encoder measuring angular position of the drive shaft"
    DTDFVocab:producedData MQTTMotorEncoderStream
]

instance GearboxSecondaryEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder behind the cycloidal gearbox measuring angular position"
    DTDFVocab:producedData MQTTGearboxEncoderStream
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring motor current I_M"
    DTDFVocab:producedData MQTTCurrentStream
]

// C4: Physical‑to‑virtual interaction (data transmitted)
instance MQTTMotorEncoderStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorMountedEncoder
]

instance MQTTGearboxEncoderStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSecondaryEncoder
]

instance MQTTCurrentStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data (raw and derived)
instance MotorEncoderAngularPositionData : DTDFVocab:Data [
    base:desc "Time‑stamped angular position data from the motor‑mounted encoder"
    DTDFVocab:fromData MQTTMotorEncoderStream
    DTDFVocab:inputTo SimulinkEnabler
]

instance GearboxEncoderAngularPositionData : DTDFVocab:Data [
    base:desc "Time‑stamped angular position data from the gearbox secondary encoder"
    DTDFVocab:fromData MQTTGearboxEncoderStream
    DTDFVocab:inputTo SimulinkEnabler
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑stamped motor current I_M measurements"
    DTDFVocab:fromData MQTTCurrentStream
    DTDFVocab:inputTo SimulinkEnabler
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Torque τ time series derived by Simulink friction models"
    DTDFVocab:inputTo DashboardEnabler
]

instance DerivedAngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity ω time series derived from encoder data"
    DTDFVocab:inputTo DashboardEnabler
]

// C10: Engineering & simulation models
instance SysMLAxisModel : DTDFVocab:Model [
    base:desc "SysML block definition & internal block diagram for motor, gearwheel and cycloidal gearbox of the first axis"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkFrictionlessGearboxModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the frictionless gearbox"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkCoulombViscousModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Coulomb‑Viscous friction"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkStribeckModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Stribeck friction characteristic"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkDahlModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Dahl friction behavior"
    DTDFVocab:inputTo SimulinkEnabler
]

instance SimulinkLuGreModel : DTDFVocab:Model [
    base:desc "Simulink model implementing LuGre friction formulation"
    DTDFVocab:inputTo SimulinkEnabler
]

// C11: Enablers (tools & platforms)
instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment processing sensor data and running friction models"
    DTDFVocab:enables FrictionIdentificationService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualizing measured vs simulated torque and angular velocity"
    DTDFVocab:enables RealTimeVisualizationService
]

instance SinumerikControllerEnabler : DTDFVocab:Enabler [
    base:desc "Siemens SINUMERIK 840D controller receiving updated friction parameters"
    DTDFVocab:enables FrictionParameterUpdateService
]

// C6: Services offered by the digital twin
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuous identification of static, kinetic and viscous friction coefficients in the gearbox"
    DTDFVocab:provides FrictionParametersInsight
]

instance RealTimeVisualizationService : DTDFVocab:Service [
    base:desc "Real‑time visualization of measured versus simulated torque and angular velocity in the dashboard"
    DTDFVocab:provides VisualizationInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generation and transmission of updated friction parameters to improve robot motion‑control accuracy"
    DTDFVocab:provides ParameterUpdateAction
]

// C17: Insights and actions derived from services
instance FrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Derived static, kinetic and viscous friction parameters are computed from live data"
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Dashboard displays side‑by‑side measured and simulated torque/velocity curves"
]

instance ParameterUpdateAction : DTDFVocab:Action [
    base:desc "Updated friction coefficients are fed back to the SINUMERIK 840D controller to refine trajectory planning"
    DTDFVocab:IsAutomatic true
]

// Optional: System component and environment
instance RobotFirstAxis : DTDFVocab:Component [
    base:desc "First axis of the MABI MAX 100 robot comprising motor, gearwheel and cycloidal gearbox"
]

instance ManufacturingEnvironment : DTDFVocab:Environment [
    base:contains RobotFirstAxis
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital shadow does not send commands back to the robot; it is a one‑way passive representation, so no virtual‑to‑physical interaction is performed."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time, continuous during robot operation; data are acquired and processed at the same rate as the sensor sampling (live streaming via MQTT)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow consisting of data trace objects (I_M, r_M, r_G, r_out, ˆr_M, ˆr_G, ˆr_out), processing components that execute the Simulink simulation models, and a visualization dashboard; all elements are linked according to the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital shadow is built on engineering models of the axis (SysML structural model) and is used in the operational phase to identify friction during run‑time; thus it spans the designed (model) and operated (runtime) stages."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each data point back to its source and processing component ensures model fidelity; simulated outputs are continuously compared with measured reference traces to validate and update the friction models."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the robot to the digital shadow using MQTT messages; the Asset Administration Shell provides the semantic linkage between the physical asset and its virtual representation."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation follows the Industry 4.0 Asset Administration Shell standard for asset representation, uses SysML (an OMG standard) for engineering models, and employs MQTT (an OASIS standard) for data transport."
]
